public class MaxFinder {
    public static int max(int[] nums) {
        int result = nums[0];
        for (int n : nums) {
            if (n > result) result = n;
        }
        return result;
    }

    public static void main(String[] args) {
        System.out.println(max(new int[]{3, 1, 4, 1, 5, 9, 2, 6}));
        System.out.println(max(new int[]{-10, -3, -7}));
    }
}
